import React from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';

const movies = [
  { 
    id: 1, 
    title: "Сны поездов", 
    poster: "https://statichdrezka.ac/i/2025/11/22/ve5f86e096f3ftl37o14l.jpg", 
    description: "История о человеке, который посвятил жизнь строительству железных дорог, но потерял связь с реальностью.",
    price: 350 
  },
  { 
    id: 2, 
    title: "Убойная суббота", 
    poster: "https://statichdrezka.ac/i/2025/10/28/w8e844c9cf3f4wn55f68z.jpg", 
    description: "Комедийный триллер о том, как обычный вечер превращается в хаос.",
    price: 400 
  },
  { 
    id: 3, 
    title: "Бугония", 
    poster: "https://statichdrezka.ac/i/2025/12/16/s2f9fa24dd993rl76z62e.jpg", 
    description: "Двое конспирологов похищают главу фармацевтической компании, уверенные, что она — пришелец.",
    price: 300 
  },
  { 
    id: 4, 
    title: "Джокер", 
    poster: "https://m.media-amazon.com/images/M/MV5BNGVjNWI4ZGUtNzE0MS00YTJmLWE0ZDctN2ZiYTk2YmI3NTYyXkEyXkFqcGdeQXVyMTkxNjUyNQ@@._V1_.jpg", 
    description: "История становления самого известного злодея Готэма.",
    price: 450 
  },
];

function DetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();

  const movie = movies.find(m => m.id === parseInt(id));

  if (!movie) {
    return <h2>Фильм не найден!</h2>;
  }

  const handleBuy = () => {
    navigate('/create-order', { state: { movieTitle: movie.title, moviePrice: movie.price } });
  };

  return (
    <div className="detail-page">
      <Link to="/" className="back-link">← Назад</Link>
      <div className="detail-content">
        <img src={movie.poster} alt={movie.title} />
        <div className="info">
          <h2>{movie.title}</h2>
          <p className="description">{movie.description}</p>
          <p><strong>Цена билета:</strong> {movie.price} сом</p>
          <button onClick={handleBuy} className="buy-btn">Купить билет</button>
        </div>
      </div>
    </div>
  );
}

export default DetailPage;
